            sorted_z(sublist(n@pre - i, n@pre, l_outer)) &&
            (forall (p: Z),
              (0 <= p && p < n@pre - i) =>
              (forall (q: Z),
                (n@pre - i <= q && q < n@pre) =>
                l_outer[p] <= l_outer[q])) &&
            IntArray::full(a, n@pre, l_outer)
    */
    for (i = 0; i < n; ++i) {
        /*@ Inv
              exists l_inner,
                0 <= i && i < n@pre &&
